59	        when(sameAttrLockAcquiredHandler.handle(req, entity, "fp"))
60	                .thenReturn(StatusOr.ok(entity));
61	
62	        StatusOr<Entity> result = handler.handle(req, entityId);
63	
64	        assertTrue(result.ok());
65	        verify(sameAttrLockAcquiredHandler).handle(req, entity, "fp");
66	
67	        verifyNoInteractions(diffAttrLockAcquiredHandler);
68	        verifyNoInteractions(sameAttrLockNotAcquiredHandler);
69	        verifyNoInteractions(diffAttrLockNotAcquiredHandler);
70	    }
71	
72	    // -------------------------------------------------------------
73	    // CASE 2: tryLock = true && fingerprint different -> DifferentAttributesWithLockAcquiredHandler
74	    // -------------------------------------------------------------
75	    @Test
76	    void testDifferentAttributesWithLockAcquired() {
77	        when(distributedLock.tryLock(anyString(), anyLong())).thenReturn(true);
78	        when(entityService.getEntity(entityId)).thenReturn(entity);
79	
80	        when(fpBuilder.build(any()))
81	                .thenReturn(FingerprintBuildResult.builder().fingerprint("newFp").build());
82	        entity.setAttributeFingerprint("oldFp");
83	
84	        when(registry.get(FingerprintCase.DIFF_ATTR_LOCK))
85	                .thenReturn(diffAttrLockAcquiredHandler);
86	
87	        when(diffAttrLockAcquiredHandler.handle(eq(req), eq(entity), eq("newFp")))
88	                .thenReturn(StatusOr.ok(entity));
89	
90	        StatusOr<Entity> result = handler.handle(req, entityId);
91	
92	        assertTrue(result.ok());
93	        verify(diffAttrLockAcquiredHandler).handle(req, entity, "newFp");
94	
95	        verifyNoInteractions(sameAttrLockAcquiredHandler);
96	        verifyNoInteractions(sameAttrLockNotAcquiredHandler);
97	        verifyNoInteractions(diffAttrLockNotAcquiredHandler);
98	    }
