8	public class RedisUtil {
9	
10	    public static String getEntityLockKey(String redisKeyPrefix, IngestionRequest req) {
11	        if (req == null) {
12	            throw new IllegalArgumentException("IngestionRequest cannot be null");
13	        }
14	
15	        String entityType = req.getEntityType();
16	        String hostId = req.getHostId();
17	        String userId = req.getUserId();
18	        String adapterId = req.getAdapterId();
19	
20	        if (entityType == null) {
21	            throw new IllegalArgumentException("entityType cannot be null");
22	        }
23	
24	        // HOST type
25	        if (entityType.equalsIgnoreCase(EntityType.HOST.toString())) {
26	            if (hostId == null || hostId.isEmpty()) {
27	                throw new IllegalArgumentException("hostId is required for HOST type");
28	            }
29	            if (adapterId == null || adapterId.isEmpty()) {
30	                throw new IllegalArgumentException("adapterId is required for HOST type");
31	            }
32	            return redisKeyPrefix + hostId + "_" + adapterId;
33	        }
34	
35	        // USER_HOST_BINDING type
36	        else if (entityType.equalsIgnoreCase(EntityType.USER_HOST_BINDING.toString())) {
37	            if (hostId == null || hostId.isEmpty()) {
38	                throw new IllegalArgumentException("hostId is required for USER_HOST_BINDING type");
39	            }
40	            if (adapterId == null || adapterId.isEmpty()) {
41	                throw new IllegalArgumentException("adapterId is required for USER_HOST_BINDING type");
42	            }
43	            if (userId == null || userId.isEmpty()) {
44	                throw new IllegalArgumentException("userId is required for USER_HOST_BINDING type");
45	            }
46	
47	            return redisKeyPrefix + hostId + "_" + adapterId + "_" + userId;
48	        }
49	
50	        throw new IllegalArgumentException("Unsupported entityType: " + entityType);
51	    }
52	
53	    public static String getEntityProcessLockKey(Entity e) {
54	        return getEntityProcessLockKey(e.getType(), e.getHostId(), e.getAdapterId(), e.getUserId());
55	    }
56	
57	    public static String getEntityProcessLockKey(EntityType type, String hostId, String adapterId, String userId) {
58	        if (EntityType.USER_HOST_BINDING.equals(type)) {
59	            return Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX + hostId + "_" + adapterId + "_" + userId;
60	        }
61	        return Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX + hostId + "_" + adapterId;
62	    }
63	
64	    public static String getExistKey(IngestionRequest req) {
65	        if (req.getEntityType().equals("HOST")) {
66	            if (req.getAdapterId() == null || req.getAdapterId().isEmpty()) {
67	                throw new IllegalArgumentException("adapterId is required for HOST type");
68	            }
69	            return Constants.RedisKeys.ENTITY_EXIST_KEY_PREFIX + req.getHostId() + "_" + req.getAdapterId();
70	        }
71	        // USER_HOST_BINDING
72	        return Constants.RedisKeys.ENTITY_EXIST_KEY_PREFIX
73	                + req.getHostId() + "_" + req.getAdapterId() + "_" + req.getUserId();
74	    }
75	}
